#!/usr/bin/env python3\n\"\"\"\nSimple test of refugee tracker integration\n\"\"\"\n\nimport sys\nfrom pathlib import Path\n\n# Add current directory to path\ncurrent_dir = Path(__file__).parent\nif str(current_dir) not in sys.path:\n    sys.path.insert(0, str(current_dir))\n\nprint(\"🧠 SIMPLE REFUGEE TRACKER INTEGRATION TEST\")\nprint(\"=\" * 50)\n\ntry:\n    # Test basic imports\n    print(\"Testing imports...\")\n    from flee.SimulationSettings import SimulationSettings\n    print(\"✅ SimulationSettings imported\")\n    \n    from flee.flee import Ecosystem, Person, Location\n    print(\"✅ Flee core classes imported\")\n    \n    from flee import moving\n    print(\"✅ Moving module imported\")\n    \n    from scripts.refugee_decision_tracker import RefugeeDecisionTracker\n    print(\"✅ RefugeeDecisionTracker imported\")\n    \n    # Test basic functionality\n    print(\"\\nTesting basic functionality...\")\n    \n    # Initialize settings\n    SimulationSettings.ReadFromYML(\"test_data/test_settings.yml\")\n    print(\"✅ Settings loaded\")\n    \n    # Create simple ecosystem\n    ecosystem = Ecosystem()\n    origin = ecosystem.addLocation(\"Origin\", x=0, y=0, movechance=1.0)\n    print(\"✅ Ecosystem created\")\n    \n    # Create agent\n    agent = Person(origin, attributes={\"connections\": 5})\n    print(\"✅ Agent created\")\n    \n    # Test existing cognitive methods\n    if hasattr(agent, 'calculate_cognitive_pressure'):\n        pressure = agent.calculate_cognitive_pressure(1)\n        print(f\"✅ Cognitive pressure: {pressure:.2f}\")\n    else:\n        print(\"⚠️  Cognitive pressure method not found\")\n    \n    # Test existing calculateMoveChance\n    SimulationSettings.move_rules[\"TwoSystemDecisionMaking\"] = True\n    movechance, system2_active = moving.calculateMoveChance(agent, False, 1)\n    print(f\"✅ Move chance: {movechance:.2f}, S2 active: {system2_active}\")\n    \n    # Test refugee tracker\n    tracker = RefugeeDecisionTracker()\n    tracker.track_refugee_decision(agent, system2_active, movechance, 1)\n    print(\"✅ Refugee decision tracked\")\n    \n    # Test analysis\n    analysis = tracker.generate_refugee_analysis_report()\n    print(f\"✅ Analysis generated: {len(analysis)} sections\")\n    \n    print(\"\\n🎉 SIMPLE INTEGRATION TEST PASSED!\")\n    \nexcept Exception as e:\n    print(f\"❌ Test failed: {e}\")\n    import traceback\n    traceback.print_exc()\n"